   636→static inline unsigned short SinglePrecisionToHalf(const float value)
   637→{
   638→  typedef union _SinglePrecision
   639→  {
   640→    unsigned int
   641→      fixed_point;
   642→
   643→    float
   644→      single_precision;
   645→  } SinglePrecision;
   646→
   647→  register int
   648→    exponent;
   649→
   650→  register unsigned int
   651→    significand,
